use aiken/collection/list
use aiken/fuzz
use cardano/assets.{lovelace_of}
use cardano/transaction.{Output, OutputReference, Transaction}
pub type CdpDatum {
  owner:             ByteArray,
  collateral:        Int,
  debt:              Int,
  liquidation_ratio: Int,
  bonus_percent:     Int,
}

pub type CdpRedeemer {
  Repay
  Liquidate
}

fn is_undercollateralized(collateral: Int, debt: Int, ratio: Int) -> Bool {
  debt > 0 && collateral * 100 < debt * ratio
}

/// Liquidator pays discounted debt: debt * (100 - bonus_percent) / 100
fn discounted_debt(debt: Int, bonus_percent: Int) -> Int {
  debt * (100 - bonus_percent) / 100
}

fn liquidator_pays_discounted(
  outputs:       List<Output>,
  owner_addr:    Output,
  debt:          Int,
  bonus_percent: Int,
) -> Bool {
  let required = discounted_debt(debt, bonus_percent)
  let paid =
    list.foldl(
      outputs,
      0,
      fn(o, acc) {
        if o.address == owner_addr.address {
          acc + lovelace_of(o.value)
        } else {
          acc
        }
      },
    )
  paid >= required
}

validator cdp_liquidation_bonus {
  spend(
    datum: Option<CdpDatum>,
    redeemer: CdpRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    when redeemer is {
      Repay -> list.has(self.extra_signatories, d.owner)
      Liquidate ->
        is_undercollateralized(d.collateral, d.debt, d.liquidation_ratio)
    }
  }
}

// ── Property tests ──────────────────────────────────────────────────────────

test prop_discounted_debt_zero_bonus(debt via fuzz.int_at_least(1)) {
  discounted_debt(debt, 0) == debt
}

test prop_discounted_debt_less_than_full(
  vals via fuzz.both(fuzz.int_at_least(100), fuzz.int_between(1, 50)),
) {
  let (debt, bonus) = vals
  discounted_debt(debt, bonus) < debt
}

test prop_discounted_debt_non_negative(
  vals via fuzz.both(fuzz.int_at_least(1), fuzz.int_between(0, 99)),
) {
  let (debt, bonus) = vals
  discounted_debt(debt, bonus) >= 0
}

test prop_undercollateralized_below_ratio(debt via fuzz.int_at_least(1)) {
  is_undercollateralized(debt * 119, debt * 100, 120)
}

// ── Negative / fail tests ────────────────────────────────────────────────────

// A position with zero debt is never undercollateralized regardless of collateral.
test prop_zero_debt_not_undercollateralized(
  vals via fuzz.both(fuzz.int_at_least(0), fuzz.int_between(1, 300)),
) fail {
  let (collateral, ratio) = vals
  expect is_undercollateralized(collateral, 0, ratio)
}

// When collateral * 100 >= debt * ratio the position is healthy, not undercollateralized.
// collateral = debt * ratio guarantees collateral * 100 == debt * ratio * 100,
// which is strictly above the threshold (needs < not <=).
test prop_well_collateralized_not_undercollateralized(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(100, 200)),
) fail {
  let (debt, ratio) = vals
  // collateral * 100 = debt * ratio * 100, so collateral * 100 >= debt * ratio
  expect is_undercollateralized(debt * ratio, debt, ratio)
}

// No outputs → paid == 0, which is less than any positive required amount.
test prop_no_outputs_liquidator_pays_nothing(
  debt via fuzz.int_between(1, 10000),
) fail {
  // bonus_percent = 0, so required = debt; paid = 0 < debt for debt >= 1
  expect liquidator_pays_discounted([], Output { address: cardano/address.from_verification_key(#"deadbeef00"), value: cardano/assets.zero, datum: cardano/transaction.NoDatum, reference_script: None }, debt, 0)
}

// A 100% bonus makes discounted_debt return 0 for any positive debt,
// but here we check that a negative bonus (overpaying expectation) never equals debt.
// More directly: bonus_percent >= 100 makes discounted_debt <= 0 for positive debt,
// confirming the helper yields a non-positive value — we prove it is NOT equal to debt
// by asserting discounted_debt with bonus=100 equals debt (which is False for debt>0).
test prop_full_bonus_discounted_debt_not_equal_original(
  debt via fuzz.int_between(1, 100000),
) fail {
  expect discounted_debt(debt, 100) == debt
}
